import{_ as s,o as a,c as t,a2 as i}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"浏览器 DevTools：Elements、Console、Network 与 Sources","description":"","frontmatter":{},"headers":[],"relativePath":"01-frontend/notes/00-web-basics/06-browser-devtools-panels.md","filePath":"01-frontend/notes/00-web-basics/06-browser-devtools-panels.md","lastUpdated":1784542968000}'),l={name:"01-frontend/notes/00-web-basics/06-browser-devtools-panels.md"};function n(o,e,r,d,h,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="浏览器-devtools-elements、console、network-与-sources" tabindex="-1">浏览器 DevTools：Elements、Console、Network 与 Sources <a class="header-anchor" href="#浏览器-devtools-elements、console、network-与-sources" aria-label="Permalink to &quot;浏览器 DevTools：Elements、Console、Network 与 Sources&quot;">​</a></h1><h2 id="是什么与为什么需要" tabindex="-1">是什么与为什么需要 <a class="header-anchor" href="#是什么与为什么需要" aria-label="Permalink to &quot;是什么与为什么需要&quot;">​</a></h2><p>DevTools 是浏览器内置诊断工具。Elements 检查实时 DOM 和计算样式；Console 查看消息并在页面上下文执行 JavaScript；Network 记录请求、响应、时序和缓存；Sources 查看资源、设置断点和单步执行。它提供运行时证据，不能只靠阅读源码替代。</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;复现问题&quot;] --&gt; B{&quot;问题表现&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;结构或样式&quot;| C[&quot;Elements / Computed&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;请求或缓存&quot;| D[&quot;Network&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;异常或状态&quot;| E[&quot;Console&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|&quot;执行路径&quot;| F[&quot;Sources / Debugger&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; G[&quot;形成可验证假设&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;修改源文件并重新验证&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>DevTools 面板不是互相替代的。一个图片未显示可能同时需要检查 DOM 中的 <code>src</code>、Network 状态和响应类型、Console 的安全错误以及 Sources 中生成 URL 的代码。</p><h2 id="四个核心面板的证据类型" tabindex="-1">四个核心面板的证据类型 <a class="header-anchor" href="#四个核心面板的证据类型" aria-label="Permalink to &quot;四个核心面板的证据类型&quot;">​</a></h2><ol><li>Elements 选择节点，在 Styles 临时切换声明，在 Computed 看最终值和来源。</li><li>Console 运行 <code>document.querySelector(&#39;main&#39;)</code>，检查错误堆栈；不要粘贴不可信代码。</li><li>打开 Network 后刷新，查看主文档的 Status、Headers、Timing、Response、Initiator。</li><li>Sources 在事件处理函数设断点，使用 Step over/into/out、Scope、Watch 定位状态变化。</li></ol><h3 id="elements-与样式" tabindex="-1">Elements 与样式 <a class="header-anchor" href="#elements-与样式" aria-label="Permalink to &quot;Elements 与样式&quot;">​</a></h3><ul><li>DOM 树显示浏览器解析后的实时节点，不一定与原始 HTML 文本相同。</li><li>Styles 显示匹配规则和被覆盖声明；Computed 显示最终计算值，并可追溯来源。</li><li>Event Listeners、Properties 和 Accessibility 视图可进一步检查事件、DOM 属性和无障碍名称。</li></ul><h3 id="network-的请求证据" tabindex="-1">Network 的请求证据 <a class="header-anchor" href="#network-的请求证据" aria-label="Permalink to &quot;Network 的请求证据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>回答的问题</th></tr></thead><tbody><tr><td>Status</td><td>HTTP 层是否成功、重定向或失败</td></tr><tr><td>Type / Content-Type</td><td>浏览器怎样解释资源，服务器声明是否正确</td></tr><tr><td>Initiator</td><td>哪个文档、样式或脚本触发请求</td></tr><tr><td>Timing</td><td>队列、连接、等待响应和下载分别耗时多少</td></tr><tr><td>Size</td><td>来自网络、内存缓存还是磁盘缓存</td></tr><tr><td>Request/Response Headers</td><td>方法、缓存、认证、跨源等协议事实</td></tr></tbody></table><p>只在客户端展示问题时导出 HAR 前，应检查其中可能包含 Cookie、Authorization、查询参数和响应数据，脱敏后再共享。</p><h3 id="sources-调试" tabindex="-1">Sources 调试 <a class="header-anchor" href="#sources-调试" aria-label="Permalink to &quot;Sources 调试&quot;">​</a></h3><p>普通断点暂停在指定行；条件断点只在表达式为真时暂停；DOM 断点可在节点变化时暂停；XHR/fetch 断点按 URL 片段暂停。Step over 执行当前行但不进入被调用函数，Step into 进入调用，Step out 运行到当前函数返回。</p><h2 id="运行时检查的关键规则" tabindex="-1">运行时检查的关键规则 <a class="header-anchor" href="#运行时检查的关键规则" aria-label="Permalink to &quot;运行时检查的关键规则&quot;">​</a></h2><ul><li>Elements 中修改默认只存在于当前页面会话，刷新会丢失。</li><li>Network 只记录面板打开后的活动；复现加载问题先打开再刷新。</li><li>“Disable cache”通常仅在 DevTools 打开时生效。</li><li>Console 当前执行上下文可能是 iframe 或扩展，不一定是顶层页面。</li><li>生产代码经过转译或压缩时，source map 决定能否映射到源文件。</li></ul><h2 id="状态码、缓存与跨浏览器边界" tabindex="-1">状态码、缓存与跨浏览器边界 <a class="header-anchor" href="#状态码、缓存与跨浏览器边界" aria-label="Permalink to &quot;状态码、缓存与跨浏览器边界&quot;">​</a></h2><p>404 是资源不存在，控制台的 CORS 报错还需看 Network 响应。缓存命中会使请求时序与首次访问不同。临时修改 DOM 不能修复源文件。DevTools 展现的是特定浏览器实现，跨浏览器问题需在目标浏览器复测。</p><h2 id="日志、节流、发起者和可访问性树" tabindex="-1">日志、节流、发起者和可访问性树 <a class="header-anchor" href="#日志、节流、发起者和可访问性树" aria-label="Permalink to &quot;日志、节流、发起者和可访问性树&quot;">​</a></h2><p>保留日志可跨导航观察；Network 节流是模拟，不等同真实网络。可从 Initiator 追踪是谁触发请求，从 Accessibility 树核对语义。</p><h2 id="完整案例的复现准备" tabindex="-1">完整案例的复现准备 <a class="header-anchor" href="#完整案例的复现准备" aria-label="Permalink to &quot;完整案例的复现准备&quot;">​</a></h2><p>准备一个路径错误的图片和一个抛出异常的按钮。先记录现象，再分别用 Network 和 Sources 找到根因，修复源文件后刷新验证。完成标准：能给出请求 URL、状态、发起者和异常堆栈；能说明临时 Styles 修改为何刷新后消失；Console 无未解释错误；键盘焦点和无障碍名称可在 Accessibility 视图核对。</p><h2 id="完整案例-商品图片和购买按钮同时失效" tabindex="-1">完整案例：商品图片和购买按钮同时失效 <a class="header-anchor" href="#完整案例-商品图片和购买按钮同时失效" aria-label="Permalink to &quot;完整案例：商品图片和购买按钮同时失效&quot;">​</a></h2><p>输入证据是页面显示图片占位，点击“加入购物车”无反应。源码包含图片元素和事件脚本，但不能先假设是同一个根因。</p><h3 id="_1-固定复现条件" tabindex="-1">1. 固定复现条件 <a class="header-anchor" href="#_1-固定复现条件" aria-label="Permalink to &quot;1. 固定复现条件&quot;">​</a></h3><p>打开 DevTools，Network 勾选 Preserve log，选择 Disable cache 后刷新。记录页面 URL、浏览器版本、视口和复现步骤。缓存禁用仅在 DevTools 打开期间生效，测试完成后要恢复正常条件再次验证。</p><h3 id="_2-用-elements-检查解析结果" tabindex="-1">2. 用 Elements 检查解析结果 <a class="header-anchor" href="#_2-用-elements-检查解析结果" aria-label="Permalink to &quot;2. 用 Elements 检查解析结果&quot;">​</a></h3><p>在 Elements 选中图片，确认实际 DOM：</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/assets/product-42.webp&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> alt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;黑色机械键盘&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;800&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;600&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>检查 Properties 中 <code>currentSrc</code>、<code>naturalWidth</code>、<code>complete</code>。<code>complete</code> 为 true 不等于成功解码，失败图片也可能处于完成状态；<code>naturalWidth</code> 为 0 是进一步证据。</p><p>再检查按钮是否真是：</p><div class="language-html vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">button</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;button&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> data-product-id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;加入购物车&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">button</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果运行时 DOM 是 <code>div</code>，问题可能在模板生成或脚本替换，不能用临时添加 <code>role</code> 作为修复。</p><h3 id="_3-在-network-定位图片失败层" tabindex="-1">3. 在 Network 定位图片失败层 <a class="header-anchor" href="#_3-在-network-定位图片失败层" aria-label="Permalink to &quot;3. 在 Network 定位图片失败层&quot;">​</a></h3><p>过滤 <code>Img</code>，选择请求并记录：</p><table tabindex="0"><thead><tr><th>观察项</th><th>实际证据</th><th>结论方向</th></tr></thead><tbody><tr><td>Request URL</td><td>是否为预期绝对 URL</td><td>路径基准是否错误</td></tr><tr><td>Status</td><td>404、403、200 等</td><td>路由、权限或响应可用性</td></tr><tr><td>Content-Type</td><td>应为受支持图片类型</td><td>服务器可能返回 HTML 错误页</td></tr><tr><td>Response</td><td>是否真是图片字节/错误文档</td><td>状态 200 也可能内容错误</td></tr><tr><td>Initiator</td><td>HTML、CSS 或脚本</td><td>找到负责生成 URL 的源</td></tr></tbody></table><p>若状态 404 且 Initiator 是主 HTML，修复 <code>src</code>。若状态 200 但 Content-Type 为 <code>text/html</code>，可能服务器把缺失资源回退到 SPA HTML；应修复服务器资源路由，不在图片元素上重试同一 URL。</p><h3 id="_4-用-console-和-sources-查按钮" tabindex="-1">4. 用 Console 和 Sources 查按钮 <a class="header-anchor" href="#_4-用-console-和-sources-查按钮" aria-label="Permalink to &quot;4. 用 Console 和 Sources 查按钮&quot;">​</a></h3><p>Console 第一条未处理异常为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TypeError: Cannot read properties of null (reading &#39;addEventListener&#39;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>点击堆栈进入 Sources，在异常处暂停。Scope 显示查询选择器返回 null，而脚本使用了 <code>.buy-button</code>，DOM 使用 <code>[data-product-id]</code>。用 Console 只读验证：</p><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">querySelector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;.buy-button&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">querySelector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;[data-product-id=&quot;42&quot;]&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>预期第一个为 null，第二个返回按钮。临时在 Console 手工绑定事件只能验证假设，刷新会丢失，最终必须修改源码。</p><h3 id="_5-验证修复的交互与网络" tabindex="-1">5. 验证修复的交互与网络 <a class="header-anchor" href="#_5-验证修复的交互与网络" aria-label="Permalink to &quot;5. 验证修复的交互与网络&quot;">​</a></h3><p>修改选择器并重新加载。设置事件监听断点或在处理函数设断点，点击按钮后检查 Call Stack、请求负载和响应。成功不只看按钮颜色，还要确认：</p><ul><li>键盘 Tab 能聚焦按钮，Enter 与 Space 能激活。</li><li>Network 中加入购物车请求方法、状态和正文符合契约。</li><li>重复点击时不会创建意外重复订单。</li><li>Console 没有未解释异常。</li><li>Accessibility 树的 Name 是“加入购物车”，Role 是 button。</li></ul><p>失败分支：如果断点命中旧代码，检查 Network 是否加载旧 bundle、source map 是否对应当前构建、Service Worker 或缓存是否拦截。若请求被 CORS 阻止，Network 仍可能显示响应线索；修复服务端跨源策略，不用关闭浏览器安全功能作为生产方案。</p><h3 id="_6-输出与证据链" tabindex="-1">6. 输出与证据链 <a class="header-anchor" href="#_6-输出与证据链" aria-label="Permalink to &quot;6. 输出与证据链&quot;">​</a></h3><p>案例输出包括修正的资源 URL、选择器与回归测试。问题记录应写明复现输入、失败请求、异常堆栈、源码位置、修复 diff 和修复后的观察结果。截图可辅助沟通，但状态、头和代码文本更适合审查与搜索。</p><h2 id="面板数据的限制" tabindex="-1">面板数据的限制 <a class="header-anchor" href="#面板数据的限制" aria-label="Permalink to &quot;面板数据的限制&quot;">​</a></h2><p>Network 节流是浏览器的模拟参数，不包含所有真实无线网络、设备 CPU 和服务端拥塞。Performance、Memory 和 Lighthouse 各有不同采样与审计模型，不能用单次分数替代真实用户数据。跨浏览器实现问题必须在目标浏览器的开发工具中复测。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://developer.chrome.com/docs/devtools/overview" target="_blank" rel="noreferrer">Chrome DevTools：Overview</a> — 访问日期：2026-07-17</li><li><a href="https://developer.chrome.com/docs/devtools/network/" target="_blank" rel="noreferrer">Chrome DevTools：Inspect network activity</a> — 访问日期：2026-07-17</li><li><a href="https://developer.chrome.com/docs/devtools/console/reference/" target="_blank" rel="noreferrer">Chrome DevTools：Console reference</a> — 访问日期：2026-07-17</li><li><a href="https://developer.chrome.com/docs/devtools/03-javascript/" target="_blank" rel="noreferrer">Chrome DevTools：JavaScript debugging</a> — 访问日期：2026-07-17</li><li><a href="https://developer.chrome.com/docs/devtools/accessibility/reference/" target="_blank" rel="noreferrer">Chrome DevTools：Accessibility features reference</a> — 访问日期：2026-07-17</li></ul>`,53)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
